      align-items: center;
      justify-content: center;
      width: 32px;
      height: 32px;
      font-size: 14px;
    }
  </style>
</head>
<body>
  <div id="graph-container"></div>

  <script>
    const s = new sigma({
      container: 'graph-container',
      settings: {
        defaultNodeColor: '#ec5148'
      }
    });

    const nodes = [
      { id: 'n0', label: 'Node 0', x: 0, y: 0 },
      { id: 'n1', label: 'Node 1', x: 100, y: 100 }
    ];

    const edges = [
      { id: 'e0', source: 'n0', target: 'n1' }
    ];

    // Add nodes and edges to Sigma.js graph
    nodes.forEach(node => s.graph.addNode(node));
    edges.forEach(edge => s.graph.addEdge(edge));

    // Render graph
    s.refresh();

    // Enable drag and drop functionality for nodes using Draggable
    const nodesWrapper = document.getElementById('graph-container');
    const nodesElements = Array.from(nodesWrapper.getElementsByClassName('node'));

    const draggableNodes = nodesElements.map(nodeElement => {
      return new Draggable(nodeElement, {
        onMove: (event) => {
          const node = s.graph.nodes(nodeElement.getAttribute('data-node-id'));
          const newPosition = s.camera.viewportToWorld({
            x: event.clientX,
            y: event.clientY
          });

          node.x = newPosition.x;
          node.y = newPosition.y;

          s.refresh();
        }
      });
    });
  </script>
</body>
</html>
```

In this alternative approach, we use the Draggable library to handle drag and drop functionality for the nodes. We initialize Draggable for each node element, and on each move event, we update the position of the corresponding node in the Sigma.js graph.

